import { useState } from "react";
import api from "../services/api";

export default function TagList({ tags = [] }) {
  const [followed, setFollowed]   = useState({});
  const [loading, setLoading]     = useState({});
  const [feedback, setFeedback]   = useState({});

  if (!tags.length) return null;

  const handleFollow = async (tag) => {
    if (followed[tag] || loading[tag]) return;
    setLoading(l => ({ ...l, [tag]: true }));
    try {
      await api.post(
        "/users/follow-tag",
        { tag },
        { headers: { Authorization: `Bearer ${localStorage.getItem("token")}` } }
      );
      setFollowed(f => ({ ...f, [tag]: true }));
      setFeedback(fb => ({ ...fb, [tag]: "followed" }));
      setTimeout(() => setFeedback(fb => ({ ...fb, [tag]: null })), 2000);
    } catch (err) {
      setFeedback(fb => ({ ...fb, [tag]: "error" }));
      setTimeout(() => setFeedback(fb => ({ ...fb, [tag]: null })), 2500);
    } finally {
      setLoading(l => ({ ...l, [tag]: false }));
    }
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Share+Tech+Mono&display=swap');

        .tl {
          display: flex; flex-wrap: wrap; gap: 8px; align-items: center;
          font-family: 'Share Tech Mono', monospace;
        }

        /* Tag chip */
        .tl-tag {
          display: inline-flex; align-items: center; gap: 0;
          border: 1px solid rgba(0,255,200,0.2);
          background: rgba(0,255,200,0.04);
          overflow: hidden;
          animation: tl-in 0.25s ease both;
        }
        @keyframes tl-in {
          from { opacity:0; transform:scale(0.88) translateY(3px); }
          to   { opacity:1; transform:scale(1)    translateY(0); }
        }

        .tl-tag:hover {
          border-color: rgba(0,255,200,0.4);
          background: rgba(0,255,200,0.07);
        }

        .tl-tag.is-followed {
          border-color: rgba(0,255,200,0.45);
          background: rgba(0,255,200,0.08);
        }

        .tl-tag.is-error {
          border-color: rgba(255,80,80,0.35);
          background: rgba(255,80,80,0.06);
        }

        /* Tag name */
        .tl-name {
          font-size: 11px; letter-spacing: 0.07em;
          color: rgba(0,255,200,0.75);
          padding: 5px 10px 5px 11px;
          user-select: none;
        }

        .tl-tag.is-followed .tl-name { color: #00ffc8; }
        .tl-tag.is-error    .tl-name { color: #ff7070; }

        /* Divider between name and button */
        .tl-sep {
          width: 1px; align-self: stretch;
          background: rgba(0,255,200,0.12);
        }

        /* Follow button */
        .tl-btn {
          display: flex; align-items: center; gap: 4px;
          padding: 5px 9px;
          background: none; border: none; cursor: pointer;
          font-family: 'Share Tech Mono', monospace;
          font-size: 9px; letter-spacing: 0.18em; text-transform: uppercase;
          color: rgba(0,255,200,0.35);
          transition: color 0.2s, background 0.2s;
          white-space: nowrap;
        }
        .tl-btn:hover:not(:disabled) {
          color: #00ffc8;
          background: rgba(0,255,200,0.08);
        }
        .tl-btn:disabled { cursor: default; }

        /* Followed state */
        .tl-tag.is-followed .tl-btn {
          color: rgba(0,255,200,0.5);
        }

        /* Error state */
        .tl-tag.is-error .tl-btn {
          color: rgba(255,80,80,0.6);
        }

        /* Spinner */
        .tl-spinner {
          display: inline-block; width: 8px; height: 8px;
          border: 1.5px solid rgba(0,255,200,0.2);
          border-top-color: #00ffc8;
          border-radius: 50%;
          animation: tl-spin 0.7s linear infinite;
        }
        @keyframes tl-spin { to { transform: rotate(360deg); } }

        /* Feedback flash */
        .tl-feedback {
          font-size: 10px; letter-spacing: 0.12em;
          padding: 4px 10px;
          animation: tl-flash 0.3s ease;
        }
        @keyframes tl-flash {
          from { opacity: 0; transform: translateX(-4px); }
          to   { opacity: 1; transform: translateX(0); }
        }
        .tl-feedback.ok  { color: #00ffc8; }
        .tl-feedback.err { color: #ff7070; }
      `}</style>

      <div className="tl">
        {tags.map((tag, i) => {
          const isFollowed = !!followed[tag];
          const isLoading  = !!loading[tag];
          const fb         = feedback[tag];
          const stateClass = fb === "error" ? "is-error" : isFollowed ? "is-followed" : "";

          return (
            <span
              key={tag}
              className={`tl-tag ${stateClass}`}
              style={{ animationDelay: `${i * 0.05}s` }}
            >
              <span className="tl-name">
                {tag}
              </span>

              <span className="tl-sep" />

              <button
                className="tl-btn"
                onClick={() => handleFollow(tag)}
                disabled={isFollowed || isLoading}
                title={isFollowed ? `Following ${tag}` : `Follow ${tag}`}
              >
                {isLoading ? (
                  <span className="tl-spinner" />
                ) : isFollowed ? (
                  <>✓ <span>On</span></>
                ) : (
                  <>+ <span>Follow</span></>
                )}
              </button>

              {fb && (
                <span className={`tl-feedback ${fb === "error" ? "err" : "ok"}`}>
                  {fb === "error" ? "⚠" : "✓"}
                </span>
              )}
            </span>
          );
        })}
      </div>
    </>
  );
}
